+// ─── Helpers ────────────────────────────────────────────────────────────────
+
+fn append_jsonl(path: &Path, line: &str) {
+    use std::io::Write;
+    let _ = std::fs::create_dir_all(path.parent().unwrap_or(Path::new(".")));
+    let mut file = std::fs::OpenOptions::new()
+        .create(true)
+        .append(true)
+        .open(path)
+        .expect("open JSONL for append");
+    let _ = writeln!(file, "{line}");
+}
